#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    int *q = (int*)malloc(T*sizeof(int));
    int maxN=0; for(int i=0;i<T;++i){scanf("%d",&q[i]); if(q[i]>maxN) maxN=q[i];}
    unsigned long long *fib = (unsigned long long*)calloc(maxN+2,sizeof(unsigned long long));
    if(maxN>=1) fib[1]=0ULL;
    if(maxN>=2) fib[2]=1ULL;
    for(int i=3;i<=maxN;++i) fib[i]=fib[i-1]+fib[i-2];
    for(int i=0;i<T;++i) printf("%llu\n",fib[q[i]]);
    free(q); free(fib);
    return 0;
}

