const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let idx = 0;
const T = parseInt(input[idx++], 10);
const queries = [];
let maxN = 0;
for (let i = 0; i < T; i++) {
  const n = parseInt(input[idx++], 10);
  queries.push(n);
  if (n > maxN) maxN = n;
}
const fib = new Array(maxN + 2).fill(0n);
if (maxN >= 2) fib[2] = 1n;
for (let i = 3; i <= maxN; i++) {
  fib[i] = fib[i-1] + fib[i-2];
}
let out = '';
for (let i = 0; i < T; i++) {
  out += fib[queries[i]].toString();
  if (i + 1 < T) out += '\n';
}
